async function submitToCBMS(invoice, config) {
	const baseUrl = config.environment === "production" ? "https://cbms.ird.gov.np/api/v1" : "https://sandbox.cbms.ird.gov.np/api/v1";
	try {
		const res = await fetch(`${baseUrl}/invoice/submit`, {
			method: "POST",
			headers: {
				"Content-Type": "application/json",
				Authorization: `Bearer ${config.clientSecret}`
			},
			body: JSON.stringify(invoice)
		});
		const data = await res.json();
		return res.ok ? {
			success: true,
			referenceNo: data.referenceNo
		} : {
			success: false,
			error: data.message
		};
	} catch {
		return {
			success: false,
			error: "Network error"
		};
	}
}
