	doc.setFontSize(FONT_SIZES.body);
	doc.setTextColor(COLORS.text[0], COLORS.text[1], COLORS.text[2]);
	doc.text(`Invoice No: ${invoice.invoiceNo}`, 114, y + 10);
	doc.text(`Date: ${invoice.date} / ${invoice.dateNepali}`, 114, y + 15);
	doc.text(`Payment Mode: ${invoice.paymentMode.toUpperCase()}`, 114, y + 20);
