	doc.setFont("Helvetica", "bold");
	doc.text("GRAND TOTAL:", 129, totalsY);
	doc.text(formatCurrency(excelRound(invoice.grandTotal)), 191, totalsY, { align: "right" });
	doc.setFont("Helvetica", "bold");
	doc.text("Amount in Words:", 15, y);
	doc.setFont("Helvetica", "normal");
	const words = numberToWords(excelRound(invoice.grandTotal));
