function generateTrialBalancePDF(rows, company, filters) {
	const doc = new jsPDF();
	const yStart = addCompanyHeader(doc, company, "Trial Balance", `Period: ${filters.startDate} to ${filters.endDate}`);
	const tableHeaders = [
		"Account Code",
		"Account Particulars",
		"Opening Dr",
		"Opening Cr",
		"Debit (FY)",
		"Credit (FY)",
		"Closing Dr",
		"Closing Cr"
	];
	const tableBody = rows.map((r) => [
		r.accountCode,
		r.accountName,
		r.openingDr > 0 ? r.openingDr.toFixed(2) : "-",
		r.openingCr > 0 ? r.openingCr.toFixed(2) : "-",
		r.debit > 0 ? r.debit.toFixed(2) : "-",
		r.credit > 0 ? r.credit.toFixed(2) : "-",
		r.closingDr > 0 ? r.closingDr.toFixed(2) : "-",
		r.closingCr > 0 ? r.closingCr.toFixed(2) : "-"
	]);
	const totals = rows.reduce((acc, val) => {
		acc.opDr = roundTo2(acc.opDr + val.openingDr);
		acc.opCr = roundTo2(acc.opCr + val.openingCr);
		acc.dr = roundTo2(acc.dr + val.debit);
		acc.cr = roundTo2(acc.cr + val.credit);
		acc.clDr = roundTo2(acc.clDr + val.closingDr);
		acc.clCr = roundTo2(acc.clCr + val.closingCr);
		return acc;
	}, {
		opDr: 0,
		opCr: 0,
		dr: 0,
		cr: 0,
		clDr: 0,
		clCr: 0
	});
	tableBody.push([
		"",
		"GRAND TOTALS",
		totals.opDr.toFixed(2),
		totals.opCr.toFixed(2),
		totals.dr.toFixed(2),
		totals.cr.toFixed(2),
		totals.clDr.toFixed(2),
		totals.clCr.toFixed(2)
	]);
	autoTable(doc, {
		startY: yStart,
		head: [tableHeaders],
		body: tableBody,
		theme: "grid",
		styles: { fontSize: FONT_SIZES.small },
		headStyles: {
			fillColor: COLORS.primary,
			textColor: [
				255,
				255,
				255
			]
		},
		columnStyles: {
			0: { cellWidth: 20 },
			1: { cellWidth: 45 },
			2: {
				cellWidth: 19,
				halign: "right"
			},
			3: {
				cellWidth: 19,
				halign: "right"
			},
			4: {
				cellWidth: 19,
				halign: "right"
			},
			5: {
				cellWidth: 19,
				halign: "right"
			},
			6: {
				cellWidth: 19,
				halign: "right"
			},
			7: {
				cellWidth: 19,
				halign: "right"
			}
		}
	});
	addPageFooter(doc, 1, 1);
	return doc.output("blob");
}
