function categorizeLiabilities(rows) {
	const categories = [
		{
			id: "sundry-creditors",
			name: "Sundry Creditors",
			keyword: ["creditor", "creditors"],
			amount: 0
		},
		{
			id: "outstanding-expenses",
			name: "Outstanding Expenses",
			keyword: ["outstanding", "expense"],
			amount: 0
		},
		{
			id: "vat-payable",
			name: "VAT Payable",
			keyword: ["vat"],
			amount: 0
		},
		{
			id: "tds-payable",
			name: "TDS Payable",
			keyword: ["tds"],
			amount: 0
		},
		{
			id: "short-term-loans",
			name: "Short-term Loans",
			keyword: [
				"loan",
				"short-term",
				"short term"
			],
			amount: 0
		},
		{
			id: "other-liabilities",
			name: "Other Liabilities",
			keyword: [],
			amount: 0
		}
	];
	rows.forEach((row) => {
		const found = categories.find((category) => category.keyword.some((keyword) => row.accountName.toLowerCase().includes(keyword)));
		if (found) found.amount += row.amount;
		else categories[categories.length - 1].amount += row.amount;
	});
	return categories.filter((row) => row.amount !== 0).map((row) => ({
		id: row.id,
		name: row.name,
		amount: row.amount,
		level: 1
	}));
}
