function exportCashFlowToExcel(data, startDate, endDate, filename = "Cash_Flow_Statement.xlsx") {
	const rows = [];
	rows.push([
		"Period",
		`${startDate} to ${endDate}`,
		""
	]);
	rows.push([]);
	rows.push([
		"A. OPERATING ACTIVITIES",
		"",
		""
	]);
	data.operating.items.forEach((item) => rows.push([
		"",
		item.label,
		item.amount
	]));
	rows.push([
		"",
		"Operating Profit Before Working Capital Changes",
		data.operating.total
	]);
	rows.push([]);
	rows.push([
		"A. WORKING CAPITAL CHANGES",
		"",
		""
	]);
	rows.push([
		"",
		"Net Cash from Operations",
		data.operating.total
	]);
	rows.push([]);
	rows.push([
		"B. INVESTING ACTIVITIES",
		"",
		""
	]);
	data.investing.items.forEach((item) => rows.push([
		"",
		item.label,
		item.amount
	]));
	rows.push([
		"",
		"Net Cash from Investing",
		data.investing.total
	]);
	rows.push([]);
	rows.push([
		"C. FINANCING ACTIVITIES",
		"",
		""
	]);
	data.financing.items.forEach((item) => rows.push([
		"",
		item.label,
		item.amount
	]));
	rows.push([
		"",
		"Net Cash from Financing",
		data.financing.total
	]);
	rows.push([]);
	rows.push([
		"",
		"Net Increase/(Decrease) in Cash",
		data.netChange
	]);
	rows.push([
		"",
		"Opening Cash & Cash Equivalents",
		data.openingCash
	]);
	rows.push([
		"",
		"Closing Cash & Cash Equivalents",
		data.closingCash
	]);
	rows.push([
		"",
		"Verified Closing Cash",
		data.openingCash + data.netChange === data.closingCash ? "VERIFIED" : "WARNING"
	]);
	const ws = XLSX.utils.aoa_to_sheet(rows);
	const wb = XLSX.utils.book_new();
	XLSX.utils.book_append_sheet(wb, ws, "Cash Flow Statement");
	XLSX.writeFile(wb, filename);
}
function generateCashFlowPDF(data, company, startDate, endDate) {
	const doc = new jsPDF();
	let y = 18;
	doc.setFont("Helvetica", "bold");
	doc.setFontSize(14);
	doc.text(company.name || "Company Name", 105, y, { align: "center" });
	y += 6;
	if (company.address) {
		doc.setFont("Helvetica", "normal");
		doc.setFontSize(9);
		doc.text(company.address, 105, y, { align: "center" });
		y += 5;
	}
	doc.setFont("Helvetica", "bold");
	doc.setFontSize(12);
	doc.text("Cash Flow Statement", 105, y, { align: "center" });
	y += 5;
	doc.setFont("Helvetica", "normal");
	doc.setFontSize(9);
	doc.text(`Period: ${startDate} to ${endDate}`, 105, y, { align: "center" });
	y += 8;
	const drawSection = (title, rows, totalLabel, totalValue) => {
		doc.setFont("Helvetica", "bold");
		doc.setFontSize(10);
		doc.text(title, 15, y);
		y += 5;
		doc.setLineWidth(.25);
		doc.line(15, y, 195, y);
		y += 6;
		doc.setFont("Helvetica", "normal");
		doc.setFontSize(9);
		rows.forEach((row) => {
			doc.text(row.label, 18, y);
			doc.text(formatNumber(row.amount), 195, y, { align: "right" });
			y += 5;
			if (y > 265) {
				doc.addPage();
				y = 20;
			}
		});
		doc.setFont("Helvetica", "bold");
		doc.text(totalLabel, 18, y);
		doc.text(formatNumber(totalValue), 195, y, { align: "right" });
		y += 10;
	};
	drawSection("A. CASH FLOWS FROM OPERATING ACTIVITIES", data.operating.items, "Operating Profit Before Working Capital Changes", data.operating.total);
	drawSection("B. CASH FLOWS FROM INVESTING ACTIVITIES", data.investing.items, "Net Cash from Investing", data.investing.total);
	drawSection("C. CASH FLOWS FROM FINANCING ACTIVITIES", data.financing.items, "Net Cash from Financing", data.financing.total);
	doc.setFont("Helvetica", "bold");
	doc.text("NET INCREASE/(DECREASE) IN CASH:", 15, y);
	doc.text(formatNumber(data.netChange), 195, y, { align: "right" });
	y += 6;
	doc.text("Opening Cash & Cash Equivalents:", 15, y);
	doc.text(formatNumber(data.openingCash), 195, y, { align: "right" });
	y += 6;
	doc.text("CLOSING CASH & CASH EQUIVALENTS:", 15, y);
	doc.text(formatNumber(data.closingCash), 195, y, { align: "right" });
	y += 8;
	const verifiedText = round2(data.openingCash + data.netChange) === round2(data.closingCash) ? "VERIFIED ✓" : "WARNING: Reconciliation mismatch";
	doc.setFont("Helvetica", "normal");
	doc.text(verifiedText, 15, y);
	return doc.output("blob");
}
function round2(value) {
	return Math.round(value * 100) / 100;
}
